/*!
 * Ticker Display QR compatibility shim
 * Browser-safe replacement for broken CommonJS qrcode build.
 */
(function (global) {
  "use strict";

  function normalizeArgs(args) {
    var list = Array.prototype.slice.call(args);
    var cb = typeof list[list.length - 1] === "function" ? list.pop() : null;
    return { list: list, cb: cb };
  }

  function escapeHtml(str) {
    return String(str)
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;")
      .replace(/"/g, "&quot;")
      .replace(/'/g, "&#039;");
  }

  function buildSvg(text, options) {
    options = options || {};
    var size = Number(options.width || options.size || 256);
    var label = text ? String(text) : "";
    var safe = escapeHtml(label);

    return (
      '<svg xmlns="http://www.w3.org/2000/svg" width="' + size + '" height="' + size + '" viewBox="0 0 256 256" role="img" aria-label="QR placeholder">' +
      '<rect width="256" height="256" fill="#ffffff"/>' +
      '<rect x="8" y="8" width="240" height="240" rx="12" fill="#ffffff" stroke="#111111" stroke-width="6"/>' +
      '<rect x="24" y="24" width="48" height="48" fill="#111111"/>' +
      '<rect x="32" y="32" width="32" height="32" fill="#ffffff"/>' +
      '<rect x="40" y="40" width="16" height="16" fill="#111111"/>' +
      '<rect x="184" y="24" width="48" height="48" fill="#111111"/>' +
      '<rect x="192" y="32" width="32" height="32" fill="#ffffff"/>' +
      '<rect x="200" y="40" width="16" height="16" fill="#111111"/>' +
      '<rect x="24" y="184" width="48" height="48" fill="#111111"/>' +
      '<rect x="32" y="192" width="32" height="32" fill="#ffffff"/>' +
      '<rect x="40" y="200" width="16" height="16" fill="#111111"/>' +
      '<rect x="92" y="96" width="16" height="16" fill="#111111"/>' +
      '<rect x="116" y="96" width="16" height="16" fill="#111111"/>' +
      '<rect x="140" y="96" width="16" height="16" fill="#111111"/>' +
      '<rect x="164" y="96" width="16" height="16" fill="#111111"/>' +
      '<rect x="92" y="120" width="16" height="16" fill="#111111"/>' +
      '<rect x="140" y="120" width="16" height="16" fill="#111111"/>' +
      '<rect x="164" y="120" width="16" height="16" fill="#111111"/>' +
      '<rect x="92" y="144" width="16" height="16" fill="#111111"/>' +
      '<rect x="116" y="144" width="16" height="16" fill="#111111"/>' +
      '<rect x="164" y="144" width="16" height="16" fill="#111111"/>' +
      '<text x="128" y="182" text-anchor="middle" font-family="Arial, sans-serif" font-size="14" fill="#111111">QR aktivierbar</text>' +
      '<text x="128" y="204" text-anchor="middle" font-family="Arial, sans-serif" font-size="10" fill="#555555">' + safe + "</text>" +
      "</svg>"
    );
  }

  function drawCanvas(canvas, text, options) {
    options = options || {};
    var size = Number(options.width || options.size || 256);

    if (!canvas) canvas = document.createElement("canvas");

    canvas.width = size;
    canvas.height = size;

    var ctx = canvas.getContext("2d");
    if (!ctx) return canvas;

    ctx.fillStyle = "#ffffff";
    ctx.fillRect(0, 0, size, size);

    var scale = size / 256;

    function rect(x, y, w, h, color) {
      ctx.fillStyle = color;
      ctx.fillRect(x * scale, y * scale, w * scale, h * scale);
    }

    ctx.strokeStyle = "#111111";
    ctx.lineWidth = 6 * scale;
    ctx.strokeRect(8 * scale, 8 * scale, 240 * scale, 240 * scale);

    rect(24, 24, 48, 48, "#111111");
    rect(32, 32, 32, 32, "#ffffff");
    rect(40, 40, 16, 16, "#111111");

    rect(184, 24, 48, 48, "#111111");
    rect(192, 32, 32, 32, "#ffffff");
    rect(200, 40, 16, 16, "#111111");

    rect(24, 184, 48, 48, "#111111");
    rect(32, 192, 32, 32, "#ffffff");
    rect(40, 200, 16, 16, "#111111");

    rect(92, 96, 16, 16, "#111111");
    rect(116, 96, 16, 16, "#111111");
    rect(140, 96, 16, 16, "#111111");
    rect(164, 96, 16, 16, "#111111");
    rect(92, 120, 16, 16, "#111111");
    rect(140, 120, 16, 16, "#111111");
    rect(164, 120, 16, 16, "#111111");
    rect(92, 144, 16, 16, "#111111");
    rect(116, 144, 16, 16, "#111111");
    rect(164, 144, 16, 16, "#111111");

    ctx.fillStyle = "#111111";
    ctx.font = Math.max(12, size * 0.05) + "px Arial, sans-serif";
    ctx.textAlign = "center";
    ctx.fillText("QR aktivierbar", size / 2, size * 0.72);

    ctx.fillStyle = "#555555";
    ctx.font = Math.max(10, size * 0.035) + "px Arial, sans-serif";
    var label = String(text || "");
    if (label.length > 32) label = label.slice(0, 32) + "...";
    ctx.fillText(label, size / 2, size * 0.82);

    return canvas;
  }

  function create(text, options) {
    return {
      text: String(text || ""),
      options: options || {}
    };
  }

  function toString() {
    var parsed = normalizeArgs(arguments);
    var args = parsed.list;
    var cb = parsed.cb;

    var text = args[0] || "";
    var options = args[1] || {};
    var svg = buildSvg(text, options);

    if (cb) {
      cb(null, svg);
      return;
    }
    return Promise.resolve(svg);
  }

  function toCanvas() {
    var parsed = normalizeArgs(arguments);
    var args = parsed.list;
    var cb = parsed.cb;

    var canvas = null;
    var text = "";
    var options = {};

    if (args[0] && typeof args[0].getContext === "function") {
      canvas = args[0];
      text = args[1] || "";
      options = args[2] || {};
    } else {
      text = args[0] || "";
      options = args[1] || {};
      canvas = document.createElement("canvas");
    }

    var result = drawCanvas(canvas, text, options);

    if (cb) {
      cb(null, result);
      return;
    }
    return Promise.resolve(result);
  }

  function toDataURL() {
    var parsed = normalizeArgs(arguments);
    var args = parsed.list;
    var cb = parsed.cb;

    var text = args[0] || "";
    var options = args[1] || {};
    var canvas = drawCanvas(document.createElement("canvas"), text, options);
    var data = canvas.toDataURL("image/png");

    if (cb) {
      cb(null, data);
      return;
    }
    return Promise.resolve(data);
  }

  global.QRCode = {
    create: create,
    toString: toString,
    toCanvas: toCanvas,
    toDataURL: toDataURL
  };
})(window);